```class Solution {
public:
    int nthUglyNumber(int n) {
        int factors[4] = {2, 3, 5, 1}; // initialize factors array with all possible prime factors
        int result = 1; // initialize result variable
        for (int i = 1; i <= n; i++) {
            int sum = 1; // initialize sum variable
            for (int j = 0; j < 4; j++) {
                if (factors[j] == i % 10) {
                    sum *= i;
                    i /= factors[j];
                }
            }
            result = sum;
        }
        return result;
    }
};```

